import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Products() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [wishlist, setWishlist] = useState(new Set());
  const [sortBy, setSortBy] = useState('newest');

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get('/api/products');
      setProducts(res.data);
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  const toggleWishlist = (productId) => {
    const newWishlist = new Set(wishlist);
    if (newWishlist.has(productId)) {
      newWishlist.delete(productId);
    } else {
      newWishlist.add(productId);
    }
    setWishlist(newWishlist);
  };

  if (loading) return <div className="loading">Loading products...</div>;

  return (
    <div style={{ padding: '40px 20px', backgroundColor: '#fff' }}>
      {/* Breadcrumb */}
      <div style={{
        fontSize: '11px',
        fontFamily: 'Helvetica, Arial, sans-serif',
        letterSpacing: '0.5px',
        color: '#000',
        marginBottom: '40px',
        textTransform: 'uppercase'
      }}>
        MEN / TOPS / NEW
      </div>

      {/* Header Section */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        marginBottom: '40px'
      }}>
        <div>
          <h1 style={{
            fontSize: '32px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            letterSpacing: '1px',
            color: '#000',
            margin: '0 0 15px 0',
            textTransform: 'uppercase'
          }}>
            NEW ARRIVALS
          </h1>
          <p style={{
            fontSize: '13px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            color: '#666',
            margin: '0',
            maxWidth: '400px',
            lineHeight: '1.6'
          }}>
            Discover our latest collection of premium pieces crafted from the finest materials.
          </p>
        </div>

        {/* Filter & Sort */}
        <div style={{
          display: 'flex',
          gap: '30px',
          alignItems: 'center'
        }}>
          <div style={{
            fontSize: '11px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            letterSpacing: '0.5px',
            cursor: 'pointer'
          }}>
            ☰ CHANGE VIEW
          </div>
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            style={{
              fontSize: '11px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              letterSpacing: '0.5px',
              border: 'none',
              background: 'transparent',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            <option value="newest">FILTER & SORT</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
            <option value="name">Name: A to Z</option>
          </select>
        </div>
      </div>

      {/* Products Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
        gap: '0',
        maxWidth: '100%'
      }}>
        {products.map((product) => (
          <Link
            key={product._id}
            to={`/product/${product._id}`}
            style={{ textDecoration: 'none' }}
          >
            <div style={{
              position: 'relative',
              backgroundColor: '#f5f5f5',
              aspectRatio: '1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              overflow: 'hidden',
              cursor: 'pointer',
              transition: 'background-color 0.3s'
            }}>
              {/* Product Image */}
              <img
                src={product.media?.featured || `/products/${product._id}.jpg`}
                alt={product.name}
                style={{
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover',
                  transition: 'transform 0.3s'
                }}
                onMouseEnter={(e) => e.target.style.transform = 'scale(1.02)'}
                onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
              />

              {/* NEW Badge */}
              <div style={{
                position: 'absolute',
                top: '15px',
                left: '15px',
                backgroundColor: '#fff',
                padding: '4px 8px',
                fontSize: '9px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '500',
                letterSpacing: '0.5px',
                zIndex: '2'
              }}>
                NEW
              </div>

              {/* Wishlist Heart */}
              <button
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  toggleWishlist(product._id);
                }}
                style={{
                  position: 'absolute',
                  top: '15px',
                  right: '15px',
                  background: 'white',
                  border: 'none',
                  width: '32px',
                  height: '32px',
                  borderRadius: '50%',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '18px',
                  zIndex: '2',
                  transition: 'transform 0.2s'
                }}
              >
                {wishlist.has(product._id) ? '♥' : '♡'}
              </button>
            </div>
          </Link>
        ))}
      </div>

      {/* Product Info Below Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
        gap: '0'
      }}>
        {products.map((product) => (
          <div key={product._id} style={{
            padding: '15px 0',
            borderTop: '1px solid #eee'
          }}>
            <h3 style={{
              fontSize: '12px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '0.5px',
              color: '#000',
              margin: '0 0 8px 0',
              textTransform: 'uppercase'
            }}>
              {product.name}
            </h3>
            <p style={{
              fontSize: '13px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '500',
              color: '#000',
              margin: '0',
              letterSpacing: '0.5px'
            }}>
              ${product.price}
            </p>
            {product.variants && product.variants[0] && (
              <p style={{
                fontSize: '11px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                color: '#999',
                margin: '5px 0 0 0',
                letterSpacing: '0.5px'
              }}>
                {product.variants[0].color}
              </p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

export default Products;
